def test_add_employee_duplicate(api_client, merged_test_data, config):
    """
    Test duplicate employee creation: HTTP 409 expected for known duplicates.
    """
    test_entries = merged_test_data(_endpoint_data_path)
    seen_entries = set()
    for entry in test_entries:
        if not all(k in entry for k in ("name", "jobTitle", "email")):
            continue

        unique_key = (entry["name"].lower(), entry["jobTitle"].lower(), entry["email"].lower())
        if unique_key in seen_entries:
            continue  # Only try duplicate creation once for a given employee

        payload = {k: entry[k] for k in ("id", "name", "jobTitle", "email") if k in entry}
        # First create (should succeed or ignore status)
        api_client.post(_ENDPOINT, json=payload)
        # Second create (should get duplicate)
        response = api_client.post(_ENDPOINT, json=payload)
        assert response.status_code == 409, (
            f"Expected HTTP 409 Conflict for duplicate employee (payload: {payload}), "
            f"got {response.status_code}, response: {response.text}"
        )
        schema_validation = validator.validate_schema_by_response(_ENDPOINT, _METHOD, "409", response)
        assert schema_validation["valid"], (
            f"OpenAPI schema validation failed for POST {_ENDPOINT} 409: {schema_validation.get('message','')}\n"
            f"Response: {response.text}"
        )
        seen_entries.add(unique_key)
